body.script:
//
(function(){
'use strict';

var API = ((document.querySelector('meta[name="qamhad:api"]')||{}).content || 'https://api.qamhad.com').replace(/\/+$/,'');
var LANG = localStorage.getItem('q-lang')==='en' ? 'en' : 'ar';
var main = document.getElementById('main');
var bar  = document.getElementById('qLoading');

/* ---------------- helpers ---------------- */
function $(s,r){return (r||document).querySelector(s);}
function $$(s,r){return Array.prototype.slice.call((r||document).querySelectorAll(s));}
function toast(m){var t=$('#toast');if(!t)return;t.textContent=m;t.classList.add('show');clearTimeout(t._t);t._t=setTimeout(function(){t.classList.remove('show');},2600);}
document.getElementById('qYear').textContent=new Date().getFullYear();

/* ---------------- theme (exact parity with the original app.js) ---------------- */
var docEl=document.documentElement;
function applyTheme(mode){
  var dark = mode==='dark' || (mode==='auto' && window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches);
  docEl.classList.toggle('dark',dark);
  var tc=$('meta[name="theme-color"]');if(tc)tc.content=dark?'#080E1A':'#16C784';
}
applyTheme(localStorage.getItem('q-theme')||'auto');
if(window.matchMedia){window.matchMedia('(prefers-color-scheme: dark)').addEventListener('change',function(){if((localStorage.getItem('q-theme')||'auto')==='auto')applyTheme('auto');});}
$('#theme-toggle').addEventListener('click',function(){
  var next=docEl.classList.contains('dark')?'light':'dark';
  localStorage.setItem('q-theme',next);applyTheme(next);
});

/* ---------------- language (EN / عربي) ---------------- */
function applyLang(){
  docEl.setAttribute('lang',LANG);
  docEl.setAttribute('dir',LANG==='en'?'ltr':'rtl');
  $$('[data-ar]').forEach(function(el){var v=el.getAttribute(LANG==='en'?'data-en':'data-ar');if(v!=null)el.textContent=v;});
  var ls=$('#lang-switch');if(ls)ls.textContent=LANG==='en'?'عربي':'EN';
}
applyLang();
$('#lang-switch').addEventListener('click',function(){
  LANG=LANG==='en'?'ar':'en';
  localStorage.setItem('q-lang',LANG);
  applyLang();
  renderPath(false);
});

/* ---------------- favourites (localStorage) ---------------- */
window.QF={
  key:'q_favs',
  all:function(){try{return JSON.parse(localStorage.getItem(this.key)||'{}');}catch(e){return {};}},
  toggle:function(btn){
    var favs=this.all();
    var type=btn.getAttribute('data-fav')||'item', id=btn.getAttribute('data-id');
    var k=type+':'+id;
    if(favs[k]){delete favs[k];btn.classList.remove('is-active');}
    else{favs[k]={type:type,id:id,title:btn.getAttribute('data-title')||'',url:btn.getAttribute('data-url')||''};btn.classList.add('is-active');}
    localStorage.setItem(this.key,JSON.stringify(favs));
  },
  mark:function(root){var favs=this.all();$$('.fav-btn',root).forEach(function(b){var k=(b.getAttribute('data-fav')||'item')+':'+b.getAttribute('data-id');if(favs[k])b.classList.add('is-active');});}
};

/* ---------------- live clock + countdown ticking ---------------- */
function liveLabel(status,start){
  status=+status;start=+start;
  if(status===2) return 'استراحة';
  if([7,8,13].indexOf(status)>=0) return 'ركلات';
  var base={1:0,3:45,5:90,6:105}[status]||0, cap={1:45,3:90,5:105,6:120}[status]||45, minute;
  if(start>1e9) minute=base+Math.floor(Math.max(0,Date.now()/1000-start)/60)+1; else minute=base+1;
  return minute>cap?(cap+'+'+(minute-cap)+"'"):(minute+"'");
}
function tickClocks(root){
  $$('[data-status][data-lt]',root).forEach(function(el){
    var s=el.getAttribute('data-ls'), t=el.getAttribute('data-lt');
    if(s!=null&&t!=null) el.textContent=liveLabel(s,t);
  });
}
function tickCountdowns(root){
  $$('[data-countdown]',root).forEach(function(el){
    var ts=+el.getAttribute('data-countdown'), diff=ts-Math.floor(Date.now()/1000);
    if(diff<0){var p=el.closest('.mh-center');return;}
    var d=Math.floor(diff/86400),h=Math.floor(diff%86400/3600),m=Math.floor(diff%3600/60),s=diff%60,g=el.querySelector.bind(el);
    function set(sel,v){var n=g('[data-cd="'+sel+'"]');if(n)n.textContent=String(v).padStart(2,'0');}
    set('d',d);set('h',h);set('m',m);set('s',s);
  });
}
var clockTimer=setInterval(function(){tickClocks(main);tickCountdowns(main);},1000);

/* ---------------- per-fragment enhancers ---------------- */
function enhance(root){
  // REVEAL FIX: the original app.css hides every `.reveal` section
  // (opacity:0) until app.js adds `.in` via IntersectionObserver. The shell
  // must do the same or all content stays invisible. Reveal immediately so
  // content is always shown, then observe only for the fade-in animation.
  var reveals=$$('.reveal',root);
  if('IntersectionObserver' in window){
    var io=new IntersectionObserver(function(ents){ents.forEach(function(en){if(en.isIntersecting){en.target.classList.add('in');io.unobserve(en.target);}});},{rootMargin:'0px 0px -5% 0px'});
    reveals.forEach(function(el){io.observe(el);});
    // Safety net: anything still hidden after 400ms (e.g. below the fold on a
    // short viewport, or IO not firing) is force-revealed so nothing is lost.
    setTimeout(function(){reveals.forEach(function(el){el.classList.add('in');});},400);
  } else {
    reveals.forEach(function(el){el.classList.add('in');});
  }
  // Stat-count rings & counters (were animated by app.js on intersect).
  $$('[data-count]',root).forEach(function(el){var v=el.getAttribute('data-count');if(v!=null)el.textContent=v;});
  // tabs
  $$('.tabs',root).forEach(function(tabs){
    tabs.addEventListener('click',function(e){
      var btn=e.target.closest('.tab');if(!btn)return;
      var name=btn.getAttribute('data-tab');
      $$('.tab',tabs).forEach(function(t){t.classList.toggle('active',t===btn);});
      $$('.tab-panel',root).forEach(function(p){p.classList.toggle('active',p.getAttribute('data-panel')===name);});
    });
  });
  // events filter segments
  $$('[data-events-filter]',root).forEach(function(seg){
    seg.addEventListener('click',function(){
      var val=seg.getAttribute('data-events-filter');
      $$('[data-events-filter]',root).forEach(function(s){s.classList.toggle('active',s===seg);});
      $$('[data-events-view]',root).forEach(function(v){v.hidden=v.getAttribute('data-events-view')!==val;});
    });
  });
  // show-more reveals
  $$('[data-show-more]',root).forEach(function(btn){
    btn.addEventListener('click',function(){
      $$(btn.getAttribute('data-show-more'),root).forEach(function(el){el.hidden=false;});
      var wrap=btn.closest('.show-more-wrap');(wrap||btn).remove();
    });
  });
  QF.mark(root);
  tickClocks(root);tickCountdowns(root);
  // count-up + rings (static apply)
  $$('.rc-fg[data-target]',root).forEach(function(fg){requestAnimationFrame(function(){fg.style.strokeDashoffset=fg.getAttribute('data-target');});});
  $$('img[loading]',root).forEach(function(img){img.loading='lazy';});
}

/* ---------------- media / stream player ---------------- */
function openModal(html){$('#qModalMount').innerHTML=html;$('#qModal').style.display='flex';}
function closeModal(){$('#qModal').style.display='none';$('#qModalMount').innerHTML='';}
$('#qModalClose').addEventListener('click',closeModal);
$('#qModal').addEventListener('click',function(e){if(e.target===this)closeModal();});
function playYouTube(id){openModal('<iframe allow="autoplay;encrypted-media;fullscreen" allowfullscreen="" style="width:100%;aspect-ratio:16/9;border:0;display:block" src="https://www.youtube.com/embed/'+id+'?autoplay=1"></iframe>');}
function playStream(src,type){
  openModal('<video id="qV" controls autoplay playsinline style="width:100%;aspect-ratio:16/9;background:#000;display:block"></video>');
  var v=$('#qV');
  if((type==='m3u8'||/\.m3u8/.test(src))&&!v.canPlayType('application/vnd.apple.mpegurl')){
    var s=document.createElement('script');s.src='https://cdn.jsdelivr.net/npm/hls.js@1.5.13/dist/hls.min.js';
    s.onload=function(){if(window.Hls&&Hls.isSupported()){var h=new Hls();h.loadSource(src);h.attachMedia(v);}else v.src=src;};
    s.onerror=function(){v.src=src;};document.head.appendChild(s);
  }else{v.src=src;}
}

/* ---------------- SEO head sync ---------------- */
function setHead(title,desc,jsonld){
  if(title)document.title=title;
  var md=$('meta[name="description"]');if(md&&desc!=null)md.content=desc;
  var c=$('link[rel="canonical"]');if(!c){c=document.createElement('link');c.rel='canonical';document.head.appendChild(c);}
  c.href=location.href;
  $$('script[data-ld]').forEach(function(s){s.remove();});
  (jsonld||[]).forEach(function(blk){var s=document.createElement('script');s.type='application/ld+json';s.setAttribute('data-ld','1');s.textContent=blk;document.head.appendChild(s);});
}

/* ---------------- router ---------------- */
var APP_RE=/^\/(matches|today|tomorrow|yesterday|live|match|watch|leagues?|teams?|players?|news|videos?|video|standings|top-scorers|scorers|search|favorites|about|privacy|terms|contact)(\/|$)/;
function isAppPath(p){return p==='/'||APP_RE.test(p);}

function renderPath(push){
  var pathname=decodeURIComponent(location.pathname)||'/';
  var search=location.search.replace(/^\?/,'').replace(/(^|&)m=1(&|$)/,'$1').replace(/&$/,'');
  var url=API+'/render.php?path='+encodeURIComponent(pathname)+'&lang='+LANG+(search?'&'+search:'');
  bar.style.display='block';main.classList.add('q-fade');
  fetch(url,{headers:{'Accept':'application/json'},credentials:'omit'})
    .then(function(r){return r.json();})
    .then(function(d){
      if(d&&d.redirect&&d.redirect!==pathname){history.replaceState({},'',d.redirect);return renderPath(false);}
      bar.style.display='none';main.classList.remove('q-fade');
      if(!d||d.html==null||d.html===''){console.warn('[Qamhad] empty fragment for',pathname,d&&d.status);return show404();}
      main.innerHTML=d.html;
      setHead(d.title,d.description,d.jsonld);
      enhance(main);
      setActiveNav(pathname);
      window.scrollTo(0,0);
      trackGA();
      try{console.log('[Qamhad] rendered',pathname,'| html',d.html.length,'bytes | reveal:',main.querySelectorAll('.reveal').length,'| cards:',main.querySelectorAll('.match-card,.standings tr,.scorer-row,.news-card,.league-block').length);}catch(e){}
    })
    .catch(function(){bar.style.display='none';main.classList.remove('q-fade');showError();});
}
function show404(){
  main.innerHTML='<div class="q-err"><svg fill="none" stroke="currentColor" stroke-width="1.6" viewBox="0 0 24 24"><circle cx="12" cy="12" r="9"/><path d="M9 9h.01M15 9h.01M8.5 15a4 4 0 0 1 7 0"/></svg><h2>الصفحة غير موجودة</h2><p><a class="btn btn-primary" href="/">العودة للرئيسية</a></p></div>';
}
function showError(){
  main.innerHTML='<div class="q-err"><svg fill="none" stroke="currentColor" stroke-width="1.6" viewBox="0 0 24 24"><path d="M12 9v4m0 4h.01M10.3 3.9 1.8 18a2 2 0 0 0 1.7 3h17a2 2 0 0 0 1.7-3L13.7 3.9a2 2 0 0 0-3.4 0z"/></svg><h2>تعذّر الاتصال بالخادم</h2><p>يرجى المحاولة بعد قليل.</p></div>';
}
function setActiveNav(pathname){
  var seg='/'+ (pathname.split('/')[1]||'');
  $$('.main-nav a,.bottom-nav a').forEach(function(a){
    var href=a.getAttribute('href');
    a.classList.toggle('active', href===seg || (seg==='/'&&href==='/matches') || (seg==='/'&&href==='/'));
  });
}
function trackGA(){if(window.gtag)gtag('event','page_view',{page_location:location.href,page_title:document.title});}

/* ---------------- click + form interception ---------------- */
document.addEventListener('click',function(e){
  // media players (event-delegated on injected content)
  var vc=e.target.closest('[data-video-card]');
  if(vc){var href=vc.getAttribute('href')||'';var ytm=href.match(/\/video\/([A-Za-z0-9_-]+)/);
    if(ytm){e.preventDefault();playYouTube(ytm[1]);return;}}
  var a=e.target.closest('a');
  if(!a)return;
  var raw=a.getAttribute('href');
  if(!raw)return;
  if(a.target==='_blank'||a.hasAttribute('download')||/^(https?:)?\/\//.test(raw)||raw.indexOf('mailto:')===0||raw.indexOf('tel:')===0||raw.charAt(0)==='#')return;
  // resolve to a same-origin pathname
  var u;try{u=new URL(raw,location.origin);}catch(err){return;}
  if(u.origin!==location.origin)return;
  var p=u.pathname;
  if(p.indexOf('/media')===0||p.indexOf('/assets')===0||p.indexOf('/api')===0||p.indexOf('/render')===0||p.indexOf('/stream')===0)return;
  if(!isAppPath(p))return;
  e.preventDefault();
  if(u.href!==location.href)history.pushState({},'',u.href);
  renderPath(true);
},false);

document.addEventListener('submit',function(e){
  var f=e.target;if(f.tagName!=='FORM')return;
  var action=f.getAttribute('action')||'';
  // search form → SPA nav
  if(/search/.test(action)||f.querySelector('input[name="q"],input[type="search"]')){
    var q=(f.querySelector('input[name="q"],input[type="search"]')||{}).value||'';
    e.preventDefault();history.pushState({},'','/search?q='+encodeURIComponent(q));renderPath(true);return;
  }
  // newsletter/push → post to API host
  if(/newsletter/.test(action)){
    e.preventDefault();
    var email=(f.querySelector('input[type="email"]')||{}).value||'';
    fetch(API+'/proxy.php?endpoint=settings',{}).catch(function(){});
    toast('شكراً لاشتراكك');f.reset();return;
  }
},false);

window.addEventListener('popstate',function(){renderPath(false);});

/* ---------------- boot ---------------- */
// If Blogger served this as its homepage but the address bar shows an app path
// (404-with-theme), we still route by pathname. Kick off the first render.
renderPath(false);

/* Analytics (optional): if a GA4 id is configured on the API, load it. */
fetch(API+'/settings.php?lang='+LANG,{headers:{'Accept':'application/json'}}).then(function(r){return r.json();}).then(function(r){
  var a=(r&&r.data&&r.data.analytics)||{};
  if(a.ga4){var s=document.createElement('script');s.async=true;s.src='https://www.googletagmanager.com/gtag/js?id='+a.ga4;document.head.appendChild(s);
    window.dataLayer=window.dataLayer||[];window.gtag=function(){dataLayer.push(arguments);};gtag('js',new Date());gtag('config',a.ga4);}
  var ad=(r&&r.data&&r.data.ads)||{};
  if(ad.adsense_client){var x=document.createElement('script');x.async=true;x.crossOrigin='anonymous';x.src='https://pagead2.googlesyndication.com/pagead/js/adsbygoogle.js?client='+ad.adsense_client;document.head.appendChild(x);}
}).catch(function(){});

})();
//
